const link = document.querySelector('#fake-link');

link.addEventListener('click', (e) => {
  // Stops the browser from navigating to the URL in the href
  e.preventDefault();

  // Now we can do whatever we want instead!
  console.log('Loading data via fetch instead of navigating...');
  document.querySelector('#content').innerText = 'New Data Loaded!';
});

